#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int segments[N][2];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &segments[i][0], &segments[i][1]);
        }
        int Q;
        scanf("%d", &Q);
        while (Q--) {
            int M;
            scanf("%d", &M);
            int points[M];
            for (int i = 0; i < M; i++) {
                scanf("%d", &points[i]);
            }
            int count = 0;
            for (int i = 0; i < N; i++) {
                int intersect = 0;
                for (int j = 0; j < M; j++) {
                    if (points[j] >= segments[i][0] && points[j] <= segments[i][1]) {
                        intersect++;
                    }
                }
                if (intersect % 2 == 1) {
                    count++;
                }
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

