code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[][] segments = new int[N][2];
            for (int i = 0; i < N; i++) {
                segments[i][0] = sc.nextInt();
                segments[i][1] = sc.nextInt();
            }
            int Q = sc.nextInt();
            while (Q-- > 0) {
                int M = sc.nextInt();
                int[] points = new int[M];
                for (int i = 0; i < M; i++) {
                    points[i] = sc.nextInt();
                }
                int count = 0;
                for (int i = 0; i < N; i++) {
                    int intersect = 0;
                    for (int j = 0; j < M; j++) {
                        if (points[j] >= segments[i][0] && points[j] <= segments[i][1]) {
                            intersect++;
                        }
                    }
                    if (intersect % 2 == 1) {
                        count++;
                    }
                }
                System.out.println(count);
            }
        }
    }
}

