const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const input = () => lines[idx++];
const T = parseInt(input());
for (let i = 0; i < T; i++) {
    const N = parseInt(input());
    const segments = [];
    for (let j = 0; j < N; j++) {
        const [L, R] = input().split(' ').map(Number);
        segments.push([L, R]);
    }
    const Q = parseInt(input());
    for (let j = 0; j < Q; j++) {
        const [M, ...points] = input().split(' ').map(Number);
        let count = 0;
        for (let k = 0; k < N; k++) {
            let intersect = 0;
            for (let l = 0; l < M; l++) {
                if (points[l] >= segments[k][0] && points[l] <= segments[k][1]) {
                    intersect++;
                }
            }
            if (intersect % 2 == 1) {
                count++;
            }
        }
        console.log(count);
    }
}

